/**
 * Entry point for the default-service.
 * Initialized with TypeScript and an HTTP framework.
 */

import { express } from 'express';

const app = express();
const PORT = process.env.PORT || 3000;

app.use(express.json());

// Health Check Endpoint
app.get('/health', (req, res) => {
  res.status(200).send({ status: 'ok' });
});

// Main application route
app.get('/', (req, res) => {
  res.status(200).send('Welcome to default-service!');
});

app.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);
});
# Dockerfile

FROM node:18-alpine

WORKDIR /app

COPY package*.json ./
RUN npm install

COPY src/ ./

EXPOSE 3000

CMD ["node", "dist/index"]
# deployment.yaml

apiVersion: apps/v1
kind: Deployment
metadata:
  name: default-service-deployment
  labels:
    app: default-service
spec:
  replicas: 2
  selector:
    matchLabels:
      app: default-service
  template:
    metadata:
      labels:
        app: default-service
    spec:
      containers:
      - name: default-service
        image: yourregistry/default-service:latest
        ports:
        - containerPort: 3000
